#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *a = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp_int);
        long long cnt = 0;
        int l = 0, r = N - 1;
        while (l < r) {
            if (a[l] + a[r] < K) {
                cnt += (r - l);
                ++l;
            } else {
                --r;
            }
        }
        printf("%lld\n", cnt);
        free(a);
    }
    return 0;
}

