import sys

def count_pairs(arr, K):
    arr.sort()
    l, r = 0, len(arr) - 1
    cnt = 0
    while l < r:
        if arr[l] + arr[r] < K:
            cnt += r - l
            l += 1
        else:
            r -= 1
    return cnt

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out_lines.append(str(count_pairs(arr, K)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

